                provider_id=key[0],
                service_url=key[1],
                model_name=key[2],
            )
        except ValueError as exc:
            raise RuntimeError(f"Unsupported LLM service: {service_id}") from exc
        self._llm_connector_cache[key] = connector
        return connector

